                    <!--=================  Back Menu End Here  =================-->\n                </div>\n            </div>\n        </header>\n        <!--================= Header Section End Here =================-->\n\n        <!--================= Wrapper Start Here =================-->\n        <div class=\"react-wrapper\">\n            <div class=\"react-wrapper-inner\">  \n                <div class=\"react-login-page react-signup-page pt---120 pb---120\">\n                    <div class=\"container\">\n                        <div class=\"row\">                            \n                            <div class=\"col-lg-12\">\n                                <div class=\"login-right-form\">\n                                    <form>\n                                        <div class=\"login-top\">\n                                            <h3>Sign Up</h3>\n                                            <p>Already have an account? <a href=\"/login\">Log in</a></p>\n                                        </div>\n                                        <p>\n                                            <label>Email</label>\n                                            <input placeholder=\"Email\" type=\"email\" id=\"email\" name=\"email\">\n                                        </p>\n                                        <p>\n                                            <label>User Name</label>\n                                            <input placeholder=\"User Name\" type=\"email\" id=\"email\" name=\"email\">\n                                        </p>\n                                        <p>\n                                            <label>Password</label>\n                                            <input placeholder=\"Password\" type=\"password\" id=\"pass\" name=\"pass\">\n                                        </p>\n                                        <p>\n                                            <label>Confirm Password</labe