function clonePage(page) {
  if (!page) {
    return null;
  }

  return {
    ...page,
    headTags: page.headTags.map((headTag) => ({
      ...headTag,
      attrs: { ...headTag.attrs },
    })),
    scripts: page.scripts.map((script) => ({ ...script })),
  };
}

function getGeneratedRootPage(route) {
  return clonePage(rootPages[route]);
}

module.exports = {
  getGeneratedRootPage,
  rootPages,
};
